# Track pending MFA verifications and temporary access tokens
PENDING_MFA = {}


def generate_totp(secret, time_step=30, digits=6):
    """Generate a TOTP code based on the shared secret."""
    key = base64.b32decode(secret, casefold=True)
    counter = int(time.time()) // time_step
    counter_bytes = struct.pack('>Q', counter)
    hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
    offset = hmac_hash[-1] & 0x0F
    truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0]
    truncated &= 0x7FFFFFFF
    code = truncated % (10 ** digits)
    return str(code).zfill(digits)


def verify_totp(secret, code, time_step=30, window=1):
    """Verify a TOTP code with a time window tolerance."""
    for offset in range(-window, window + 1):
        key = base64.b32decode(secret, casefold=True)
        counter = (int(time.time()) // time_step) + offset
        counter_bytes = struct.pack('>Q', counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        off = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[off:off + 4])[0]
        truncated &= 0x7FFFFFFF
        expected = str(truncated % (10 ** 6)).zfill(6)
        if hmac.compare_digest(expected, code):
            return True
    return False


def login_required(f):
    """Decorator to require at least password authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({"error": "Authentication required", "redirect": "/login"}), 401
        return f(*args, **kwargs)
    return decorated_function


def mfa_required(f):
    """Decorator to require full MFA authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('authenticated'):
            return jsonify({"error": "Authentication required", "redirect": "/login"}), 401
        username = session.get('username')
        user = USERS.get(username)
        if user and user.get('mfa_enabled') and not session.get('mfa_verified'):
            return jsonify({
                "error": "MFA verification required",
                "redirect": "/verify-mfa",
                "mfa_pending": True
            }), 403
        return f(*args, **kwargs)
    return decorated_function


