@app.route('/')
def index():
    if session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        if session.get('authenticated'):
            return redirect(url_for('dashboard'))
        return render_template_string(LOGIN_TEMPLATE, error=None)

    # Handle both form and JSON requests
    if request.is_json:
        data = request.get_json()
        username = data.get('username', '')
        password = data.get('password', '')
    else:
        username = request.form.get('username', '')
        password = request.form.get('password', '')

    # Validate credentials
    user = USERS.get(username)
    if not user:
        error_msg = "Invalid username or password"
        if request.is_json:
            return jsonify({"error": error_msg}), 401
        return render_template_string(LOGIN_TEMPLATE, error=error_msg)

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if not hmac.compare_digest(password_hash, user['password_hash']):
        error_msg = "Invalid username or password"
        if request.is_json:
            return jsonify({"error": error_msg}), 401
        return render_template_string(LOGIN_TEMPLATE, error=error_msg)

    # Password verified - grant limited access
    session['authenticated'] = True
    session['username'] = username
    session['mfa_verified'] = False
    session['login_time'] = time.time()

    # If MFA is enabled, redirect to MFA verification
    if user.get('mfa_enabled') and user.get('mfa_secret'):
        # Create pending MFA entry
        PENDING_MFA[username] = {
            'timestamp': time.time(),
            'attempts': 0,
            'max_attempts': 5,
        }

        if request.is_json:
            return jsonify({
                "message": "Password verified. MFA verification required.",
                "authenticated": True,
                "mfa_required": True,
                "mfa_verified": False,
                "redirect": "/verify-mfa",
                "access_level": "limited",
            }), 200
        return redirect(url_for('verify_mfa'))

    # No MFA - full access
    session['mfa_verified'] = True
    if request.is_json:
        return jsonify({
            "message": "Login successful",
            "authenticated": True,
            "mfa_required": False,
            "mfa_verified": True,
            "redirect": "/dashboard",
            "access_level": "full",
        }), 200
    return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session.get('username')
    user = USERS.get(username)

    if not user or not user.get('mfa_enabled'):
        session['mfa_verified'] = True
        if request.is_json:
            return jsonify({"message": "MFA not required", "mfa_verified": True}), 200
        return redirect(url_for('dashboard'))

    if session.get('mfa_verified'):
        if request.is_json:
            return jsonify({"message": "MFA already verified", "mfa_verified": True}), 200
        return redirect(url_for('dashboard'))

    if request.method == 'GET':
        current_code = generate_totp(user['mfa_secret'])
        if request.is_json:
            return jsonify({
                "message": "MFA verification required",
                "mfa_verified": False,
                "hint": f"Current TOTP code (demo only): {current_code}",
            }), 200
        return render_template_string(MFA_TEMPLATE, error=None, current_code=current_code)

    # POST - verify MFA code
    if request.is_json:
        data = request.get_json()
        mfa_code = data.get('mfa_code', '')
    else:
        mfa_code = request.form.get('mfa_code', '')

    # Check rate limiting
    pending = PENDING_MFA.get(username, {})
    if pending.get('attempts', 0) >= pending.get('max_attempts', 5):
        error_msg = "Too many failed attempts. Please login again."
        session.clear()
        if request.is_json:
            return jsonify({"error": error_msg, "redirect": "/login"}), 429
        return redirect(url_for('login'))

    # Verify the TOTP code
    if verify_totp(user['mfa_secret'], mfa_code):
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()

        # Clean up pending MFA
        PENDING_MFA.pop(username, None)

        if request.is_json:
            return jsonify({
                "message": "MFA verification successful",
                "mfa_verified": True,
                "access_level": "full",
                "redirect": "/dashboard",
            }), 200
        return redirect(url_for('dashboard'))

    # Invalid code
    if username in PENDING_MFA:
        PENDING_MFA[username]['attempts'] = PENDING_MFA[username].get('attempts', 0) + 1
        remaining = PENDING_MFA[username]['max_attempts'] - PENDING_MFA[username]['attempts']
    else:
        remaining = 0

    error_msg = f"Invalid MFA code. {remaining} attempts remaining."
    current_code = generate_totp(user['mfa_secret'])

    if request.is_json:
        return jsonify({"error": error_msg, "attempts_remaining": remaining}), 401
    return render_template_string(MFA_TEMPLATE, error=error_msg, current_code=current_code)


@app.route('/api/background-mfa-check', methods=['POST'])
@login_required
def background_mfa_check():
    """Background MFA verification endpoint - allows MFA to be verified asynchronously."""
    username = session.get('username')
    user = USERS.get(username)

    if not user or not user.get('mfa_enabled'):
        return jsonify({"mfa_verified": True, "message": "MFA not required"}), 200

    if session.get('mfa_verified'):
        return jsonify({"mfa_verified": True, "message": "Already verified"}), 200

    data = request.get_json() or {}
    mfa_code = data.get('mfa_code', '')

    if not mfa_code:
        return jsonify({
            "mfa_verified": False,
            "message": "MFA code required",
            "hint": f"Current code (demo): {generate_totp(user['mfa_secret'])}",
        }), 200

    if verify_totp(user['mfa_secret'], mfa_code):
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()
        PENDING_MFA.pop(username, None)
        return jsonify({"mfa_verified": True, "message": "MFA verified successfully", "access_level": "full"}), 200

    return jsonify({"mfa_verified": False, "message": "Invalid MFA code"}), 401


