@app.route('/setup-mfa', methods=['GET', 'POST'])
@login_required
def setup_mfa():
    """Setup MFA for users who don't have it enabled."""
    username = session.get('username')
    user = USERS.get(username)

    if not user:
        return redirect(url_for('login'))

    # Generate a new secret if user doesn't have one
    if not user.get('mfa_secret'):
        user['mfa_secret'] = base64.b32encode(os.urandom(20)).decode('utf-8')

    if request.method == 'GET':
        current_code = generate_totp(user['mfa_secret'])
        return render_template_string(
            SETUP_MFA_TEMPLATE,
            mfa_secret=user['mfa_secret'],
            current_code=current_code,
            error=None,
            success=None,
        )

    # POST - verify setup
    mfa_code = request.form.get('mfa_code', '')

    if verify_totp(user['mfa_secret'], mfa_code):
        user['mfa_enabled'] = True
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()

        current_code = generate_totp(user['mfa_secret'])
        return render_template_string(
            SETUP_MFA_TEMPLATE,
            mfa_secret=user['mfa_secret'],
            current_code=current_code,
            error=None,
            success="MFA has been enabled successfully! You now have full access.",
        )

    current_code = generate_totp(user['mfa_secret'])
    return render_template_string(
        SETUP_MFA_TEMPLATE,
        mfa_secret=user['mfa_secret'],
        current_code=current_code,
        error="Invalid code. Please try again.",
        success=None,
    )


@app.route('/logout')
def logout():
    username = session.get('username')
    PENDING_MFA.pop(username, None)
    session.clear()
    if request.is_json:
        return jsonify({"message": "Logged out successfully"}), 200
    return redirect(url_for('login'))


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json() or {}
    username = data.get('username', '')
    password = data.get('password', '')

    if not username or not password:
        return jsonify({"error": "Username and password required"}), 400

    if username in USERS:
        return jsonify({"error": "Username already exists"}), 409

    if len(password) < 6:
        return jsonify({"error": "Password must be at least 6 characters"}), 400

    USERS[username] = {
        "password_hash": hashlib.sha256(password.encode()).hexdigest(),
        "mfa_secret": base64.b32encode(os.urandom(20)).decode('utf-8'),
        "mfa_enabled": False,
    }

    return jsonify({
        "message": "User registered successfully",
        "username": username,
        "mfa_enabled": False,
        "setup_mfa_url": "/setup-mfa",
    }), 201


# Cleanup old pending MFA entries periodically
@app.before_request
def cleanup_pending_mfa():
    """Clean up expired pending MFA entries (older than 10 minutes)."""
    current_time = time.time()
    expired = [
        username for username, data in PENDING_MFA.items()
        if current_time - data.get('timestamp', 0) > 600
    ]
    for username in expired:
        del PENDING_MFA[username]


